sem_Morphism_Idn (_c) (_morPos) (_lhs_cDef) =
    let ( _c_concept,_c_nm) =
            (_c (_lhs_cDef))
    in  (Idn (head ([con| con <- _lhs_cDef , _c_nm == name con]++[_c_concept])) _morPos,"I",[])
sem_Morphism_Mor :: (String) ->
                    (T_Concept) ->
                    (T_Concept) ->
                    ([Prop]) ->
                    (String) ->
                    (String) ->
                    (String) ->
                    ([Drecord]) ->
                    (FilePos) ->
                    (T_Morphism)
sem_Morphism_Mor (_nm) (_a) (_b) (_props) (_prL) (_prM) (_prR) (_content) (_morPos) (_lhs_cDef) =
    let ( _a_concept,_a_nm) =
            (_a (_lhs_cDef))
        ( _b_concept,_b_nm) =
            (_b (_lhs_cDef))
    in  (Mor _nm (C _a_nm []) (C _b_nm []) _props _prL _prM _prR _content _morPos
        ,_nm
        ,if _a_nm == _b_nm then [] else
         let ps = _props `isc` [Trn,Rfx,Sym,Asy] in
         if null ps then []
         else ["6 in "++show _morPos++"\n   Heterogeneous relation "++
               _nm++"["++ _a_nm ++"*"++ _b_nm ++
               "]\n   may not be declared "++commaAnd [pMeaning p| p<-ps]++
               ".\n   (This relation is heterogeneous because "++ _a_nm ++" and "++ _b_nm ++
               "\n   are different concepts)."]
        )
