      ms
      is
      s

-}
{-
   local variables for Rule.Hc:
      r
      is
      s

-}
-- semantic domain
type T_Rule = (Concepts) ->
              (GenR) ->
              (Morphisms) ->
              (Int) ->
              ((Gens),(Rules),([String]))
-- cata
sem_Rule :: (Rule) ->
            (T_Rule)
sem_Rule ((Dc (_defd) (_rulePos) (_expr) (_expl) (_sgn) (_nr))) =
    (sem_Rule_Dc ((sem_Morph (_defd))) (_rulePos) ((sem_Factor (_expr))) (_expl) (_sgn) (_nr))
sem_Rule ((Gc (_gluePos) (_m) (_expr) (_sgn) (_nr))) =
    (sem_Rule_Gc (_gluePos) ((sem_Morph (_m))) ((sem_Factor (_expr))) (_sgn) (_nr))
sem_Rule ((Hc (_antc) (_rulePos) (_cons) (_expl) (_sgn) (_nr))) =
    (sem_Rule_Hc ((sem_Factor (_antc))) (_rulePos) ((sem_Factor (_cons))) (_expl) (_sgn) (_nr))
sem_Rule_Dc :: (T_Morph) ->
               (FilePos) ->
               (T_Factor) ->
               (String) ->
               ((Concept,Concept)) ->
               (Int) ->
               (T_Rule)
sem_Rule_Dc (_defd) (_rulePos) (_expr) (_expl) (_sgn) (_nr) (_lhs_cDef) (_lhs_gE) (_lhs_mDef) (_lhs_nr) =
    let (_s) =
            irred _lhs_gE
             [ (lub _lhs_gE a a',lub _lhs_gE b b')
             | (a,b) <- _expr_signs, (a',b') <- _defd_signs
             , order _lhs_gE a' a && order _lhs_gE b' b]
        (_is) =
            if null _defd_signs
            then if null _expr_signs
                 then error ("in "++show _rulePos++"(fatal error)")
                 else _expr_signs
            else if null _expr_signs
                 then _defd_signs
                 else _s
        (_r) =
            Dc _defd_morph _rulePos _expr_factor _expl (if null _is then error("null @is on "++show _rulePos++"\n@defd.morph = "++show _defd_morph++"\n@defd.signs = "++show _defd_signs++"\n@expr.factor = "++show _expr_factor++"\n@expr.signs = "++show _expr_signs) else head _is) _lhs_nr
        ( _defd_atts,_defd_id,_defd_morph,_defd_mors,_defd_nm,_defd_pos,_defd_sErr,_defd_signs) =
            (_defd (_lhs_cDef) (_lhs_gE) (if null _is then _defd_signs else _is) (_lhs_mDef))
        ( _expr_factor,_expr_sErr,_expr_signs) =
            (_expr (_lhs_cDef) (_lhs_gE) (if null _is then _expr_signs else _is) (_lhs_mDef))
    in  ([]
        ,[ _r ]
        ,let sh (Mph nm pos [] _ _) sgns = nm++" :: "++show sgns
             sh (Mph nm pos as _ _) sgns = nm++show as
             sh (Id pos [] _) sgns = "I"++" :: "++show sgns
             sh (Id pos cs _) sgns = "I"++show cs
         in take 1
          ([ "0 in "++show _rulePos++"\n   Meaningless rule."
           | null _defd_signs && null _expr_signs ]++
           [ "1 in "++show _rulePos++"\n   Mismatch in rule:\n   "++
             sh _defd_morph _defd_signs ++ " does not match\n   "++
             show _expr_factor++ " :: "++show _expr_signs
           | null _is && not (null _defd_signs) && not (null _expr_signs)]++
           _defd_sErr ++ _expr_sErr ++
           [ "2 in "++show _rulePos++"\n   Ambiguous signatures: "++commaAnd (map showSign _is)++
             "\n   in right hand side:  "++ show _expr_factor++
             "\n   and left hand side:  "++ show _defd_morph
           | length _is>1])
        )
sem_Rule_Gc :: (FilePos) ->
               (T_Morph) ->
               (T_Factor) ->
               ((Concept,Concept)) ->
               (Int) ->
               (T_Rule)
sem_Rule_Gc (_gluePos) (_m) (_expr) (_sgn) (_nr) (_lhs_cDef) (_lhs_gE) (_lhs_mDef) (_lhs_nr) =
    let (_s) =
            irred _lhs_gE
             [ (lub _lhs_gE a a',lub _lhs_gE b b')
             | (a,b) <- _expr_signs, (a',b') <- _m_signs
             , order _lhs_gE a' a && order _lhs_gE b' b]
        (_is) =
            if null _m_signs
            then if null _expr_signs
                 then error ("in "++show _gluePos++"(fatal error)")
                 else _expr_signs
            else if null _expr_signs
                 then _m_signs
                 else _s
        (_ms) =
            if null _expr_signs then _m_mors else
            [ m| m <- _m_mors
               , or[s `_lhs_gE` source m && t `_lhs_gE` target m| (s,t) <- _expr_signs ]]
        (_esign) =
            irred _lhs_gE _expr_signs
        ( _m_atts,_m_id,_m_morph,_m_mors,_m_nm,_m_pos,_m_sErr,_m_signs) =
            (_m (_lhs_cDef) (_lhs_gE) (irred _lhs_gE [(source m,target m)| m <- _ms]) (_lhs_mDef))
        ( _expr_factor,_expr_sErr,_expr_signs) =
            (_expr (_lhs_cDef) (_lhs_gE) (if null _is then _expr_signs else _is) (_lhs_mDef))
    in  (clearG [g| (d,c) <- _expr_signs, m <- _m_mors, g<-[G d (source m), G c (target m)]]
        ,[Gc _gluePos (Mph _m_nm _m_pos _m_atts sgn m) (_expr_factor) sgn 0
         | (d,c) <- _expr_signs, m <- _m_mors
         , d `_lhs_gE` source m, c `_lhs_gE` target m
         , sgn<-[if null _m_atts then (source m,target m) else (head _m_atts,last _m_atts)]]
        ,let sh (Mph nm pos [] _ _) [] = nm
             sh (Mph nm pos [] _ _) sgns = nm++" :: "++show sgns
             sh (Mph nm pos as _ _) sgns = nm++show as
             sh (Id pos [] _) sgns = "I"++" :: "++show sgns
             sh (Id pos cs _) sgns = "I"++show cs
         in take 1
          ([ "13 in "++show _gluePos++
             "\n   I not allowed as left hand side of GLUE"
           | null _ms && _m_id] ++
           ["14 in "++show _gluePos++"\n   I not allowed as right hand side of GLUE"| null _expr_signs]++
           _m_sErr ++ _expr_sErr ++
           ["12 in "++show _gluePos++"\n   Mismatch in GLUE:\n   "++ _m_nm++" :: "++
                 show _m_signs++
                 "  does not match\n   "++
                 show _expr_factor++" :: "++show _expr_signs
           | null _s && not (null _m_signs && null _expr_signs) ]
           )
        )
sem_Rule_Hc :: (T_Factor) ->
               (FilePos) ->
               (T_Factor) ->
               (String) ->
               ((Concept,Concept)) ->
               (Int) ->
               (T_Rule)
sem_Rule_Hc (_antc) (_rulePos) (_cons) (_expl) (_sgn) (_nr) (_lhs_cDef) (_lhs_gE) (_lhs_mDef) (_lhs_nr) =
    let (_s) =
            irred _lhs_gE
             [ (lub _lhs_gE a a',lub _lhs_gE b b')
             | (a,b) <- _cons_signs, (a',b') <- _antc_signs
             , order _lhs_gE a' a && order _lhs_gE b' b]
        (_is) =
            if null _antc_signs
            then if null _cons_signs
                 then error ("in "++show _rulePos++"(fatal error)")
                 else _cons_signs
            else if null _cons_signs
                 then _antc_signs
                 else _s
        (_r) =
            Hc _antc_factor _rulePos _cons_factor _expl (if null _is then error("null @is on "++show _rulePos++"\n@antc.factor = "++show _antc_factor++"\n@antc.signs = "++show _antc_signs++"\n@cons.factor = "++show _cons_factor++"\n@cons.signs = "++show _cons_signs) else head _is) _lhs_nr
        ( _antc_factor,_antc_sErr,_antc_signs) =
            (_antc (_lhs_cDef) (_lhs_gE) (if null _is then _antc_signs else _is) (_lhs_mDef))
        ( _cons_factor,_cons_sErr,_cons_signs) =
            (_cons (_lhs_cDef) (_lhs_gE) (if null _is then _cons_signs else _is) (_lhs_mDef))
    in  ([]
        ,[ _r ]
        ,take 1
          ([ "0 in "++show _rulePos++"\n   Meaningless rule."
           | null _antc_signs && null _cons_signs ]++
           [ "1 in "++show _rulePos++"\n   Mismatch in rule:\n   "++
             show _antc_factor++ " :: "++show _antc_signs ++ " does not match\n   "++
             show _cons_factor++ " :: "++show _cons_signs
           | null _is && not (null _antc_signs) && not (null _cons_signs)]++
           _antc_sErr ++ _cons_sErr ++
           [ "2 in "++show _rulePos++"\n   Ambiguous signatures: "++commaAnd (map showSign _is)++
             "\n   in right hand side:  "++ show _cons_factor++
             "\n   and left hand side:  "++ show _antc_factor
           | length _is>1])
        )
