            (_f (_lhs_cDef) (_lhs_gE) ([ (b,a)| (a,b) <- _lhs_isign]) (_lhs_mDef))
    in  (_f_sErr,[ (b,a)| (a,b) <- _f_signs],Tf _f_morph (target _f_morph, source _f_morph))
