{-
   inherited attributes:
      cDef                 : Concepts
      gE                   : GenR
      isign                : [(Concept,Concept)]
      mDef                 : Morphisms

   chained attributes:

   synthesised attributes:
      list                 : Terms
      sErr                 : [String]
