-}
{-
   local variables for Terms.Cons:
      tripls
      s

-}
{-
   local variables for Terms.Nil:

-}
-- semantic domain
type T_Terms = (Concepts) ->
               (GenR) ->
               ([(Concept,Concept)]) ->
               (Morphisms) ->
               ((Terms),([String]),([(Concept,Concept)]))
-- cata
sem_Terms :: (Terms) ->
             (T_Terms)
sem_Terms (list) =
    (foldr (sem_Terms_Cons) (sem_Terms_Nil) ((map sem_Term list)))
sem_Terms_Cons :: (T_Term) ->
                  (T_Terms) ->
                  (T_Terms)
sem_Terms_Cons (_hd) (_tl) (_lhs_cDef) (_lhs_gE) (_lhs_isign) (_lhs_mDef) =
    let (_s) =
            if null _tl_signs
            then if null _hd_signs
                 then []
                 else _hd_signs
            else if null _hd_signs
                 then _tl_signs
                 else rd [(a,b)| (a,i,b) <- _tripls    ]
        (_tripls) =
            rd [(a,lub _lhs_gE b a',b')| (a,b)<- _hd_signs, (a',b')<- _tl_signs, order _lhs_gE b a']
        ( _hd_sErr,_hd_signs,_hd_term) =
            (_hd (_lhs_cDef)
                 (_lhs_gE)
                 (if null _tl_list  then _lhs_isign else
                  if null _tl_signs then _lhs_isign else
                  if null _hd_signs then irred _lhs_gE [(d,i)| (i,b) <- _tl_signs,     (d,c) <- _lhs_isign] else
                                         irred _lhs_gE [(d,i)| (a,i,b) <- _tripls    , (d,c) <- _lhs_isign, a `_lhs_gE` d && b `_lhs_gE` c])
                 (_lhs_mDef))
        ( _tl_list,_tl_sErr,_tl_signs) =
            (_tl (_lhs_cDef)
                 (_lhs_gE)
                 (if null _tl_list                    then [error "something wrong"] else
                  if null _hd_signs then _lhs_isign else
                  if null _tl_signs then irred _lhs_gE [(i,c)| (a,i)   <- _hd_signs,   (d,c) <- _lhs_isign] else
                                         irred _lhs_gE [(i,c)| (a,i,b) <- _tripls    , (d,c) <- _lhs_isign, a `_lhs_gE` d && b `_lhs_gE` c])
                 (_lhs_mDef))
    in  (_hd_term : _tl_list
        ,[ "5 in "++show (pos (head _tl_list))++"\n   Type error in composing\n   "++name _hd_term++show _hd_signs++
           " with\n   "++show (F _tl_list (C "" [],C "" []))++show _tl_signs
         | not (null _tl_list)
         , not (null _hd_signs) && not (null _tl_signs) && null _s
         ]++ _hd_sErr ++ _tl_sErr
        ,if null _tl_list then _hd_signs else _s
        )
sem_Terms_Nil :: (T_Terms)
sem_Terms_Nil (_lhs_cDef) (_lhs_gE) (_lhs_isign) (_lhs_mDef) =
    let 
    in  ([],[],[])

